mapper.select:
select from sys_agent_app
del_flag = '0' and app_name like concat('%', #{appName}, '%') and app_type = #{appType} and model_code like concat('%', #{modelCode}, '%') and status = #{status}
order by is_default desc, app_id desc

select s.*, a.app_name, a.model_code from sys_agent_session s inner join sys_agent_app a on a.app_id = s.app_id
where s.user_id = #{userId}
and s.app_id = #{appId}
order by s.last_message_time desc, s.session_id desc

select k.*, (select count(1) from sys_agent_knowledge_doc d where d.kb_id = k.kb_id) doc_count from sys_agent_knowledge_base k

    k.del_flag = '0'
    and k.kb_name like concat('%', #{kbName}, '%')
    and k.visibility = #{visibility}
    and k.status = #{status}

order by k.kb_id desc

select d.*, k.kb_name from sys_agent_knowledge_doc d left join sys_agent_knowledge_base k on k.kb_id = d.kb_id
d.kb_id = #{kbId}
order by d.doc_id desc

mapper.update:
update sys_agent_knowledge_doc
parse_status = #{parseStatus}, error_msg = #{errorMsg}, chunk_count = #{chunkCount}, update_by = #{updateBy}, update_time = sysdate()
where doc_id = #{docId}

mapper.select:
select c.*, d.file_name, k.kb_name from sys_agent_knowledge_chunk c
left join sys_agent_knowledge_doc d on d.doc_id = c.doc_id
left join sys_agent_knowledge_base k on k.kb_id = c.kb_id

    c.kb_id in #{id}
    and c.chunk_text like concat('%', #{query}, '%')

order by c.chunk_id desc limit #{limit}

select * from sys_agent_workflow
del_flag = '0' and workflow_name like concat('%', #{workflowName}, '%') and status = #{status}
order by workflow_id desc

select r.*, w.workflow_name from sys_agent_workflow_run r left join sys_agent_workflow w on w.workflow_id = r.workflow_id
r.workflow_id = #{workflowId}and r.status = #{status}
order by r.run_id desc

select * from sys_agent_tool_call

    user_id = #{userId}
    and session_id = #{sessionId}
    and workflow_run_id = #{workflowRunId}
    and tool_name like concat('%', #{toolName}, '%')

order by tool_call_id desc

mapper.update:
update sys_agent_action_draft
status = #{status}, result_msg = #{resultMsg}, error_msg = #{errorMsg}, confirm_time = #{confirmTime}, update_time = sysdate()
where draft_id = #{draftId} and user_id = #{userId}
